import { useEffect, useState } from "react";
import {
  collection,
  getDocs,
  updateDoc,
  doc,
} from "firebase/firestore";
import { db } from "../firebase";
import Swal from "sweetalert2";
import Navbar from "../components/Navbar";

export default function GerenciarAssembleias() {
  const [assembleias, setAssembleias] = useState([]);
  const [votos, setVotos] = useState([]);
  const [usuarios, setUsuarios] = useState([]);
  const [assembleiaSelecionada, setAssembleiaSelecionada] = useState(null);
  const [filtro, setFiltro] = useState("todas");
  const [busca, setBusca] = useState("");
  const [loading, setLoading] = useState(true);

  // 🔹 Carrega assembleias, usuários e votos
  useEffect(() => {
    const carregar = async () => {
      try {
        const [snapAssembleias, snapUsuarios, snapVotos] = await Promise.all([
          getDocs(collection(db, "assembleias")),
          getDocs(collection(db, "usuarios")),
          getDocs(collection(db, "votos")),
        ]);

        setAssembleias(
          snapAssembleias.docs.map((d) => ({ id: d.id, ...d.data() }))
        );
        setUsuarios(snapUsuarios.docs.map((d) => d.data()));
        setVotos(snapVotos.docs.map((d) => d.data()));
      } catch (error) {
        console.error("Erro ao carregar assembleias:", error);
      } finally {
        setLoading(false);
      }
    };
    carregar();
  }, []);

  // 🔹 Alternar status da assembleia
  const alternarStatus = async (id, statusAtual) => {
    const novoStatus = statusAtual === "ativa" ? "inativa" : "ativa";
    try {
      await updateDoc(doc(db, "assembleias", id), { status: novoStatus });
      Swal.fire({
        title: "Sucesso!",
        text: `A assembleia foi marcada como ${novoStatus}.`,
        icon: "success",
        confirmButtonColor: "#4f46e5",
      });
      setAssembleias((prev) =>
        prev.map((a) => (a.id === id ? { ...a, status: novoStatus } : a))
      );
    } catch (error) {
      console.error(error);
      Swal.fire("Erro", "Não foi possível atualizar o status.", "error");
    }
  };

  // 🔹 Ver participação (quem votou / não votou)
  const verParticipacao = (assembleia) => {
    setAssembleiaSelecionada(assembleia);
  };

  // 🔹 Filtrar assembleias
  const assembleiasFiltradas = assembleias
    .filter((a) =>
      filtro === "todas" ? true : a.status === filtro
    )
    .filter((a) =>
      a.titulo.toLowerCase().includes(busca.toLowerCase())
    );

  // 🔹 Calcula participação
  const getParticipacao = (idAssembleia) => {
    const votosDaAssembleia = votos.filter(
      (v) => v.idAssembleia === idAssembleia
    );
    const votaram = votosDaAssembleia.map(
      (v) => `${v.bloco}-${v.apartamento}`
    );
    const todosApartamentos = usuarios
      .filter((u) => u.role === "morador")
      .map((u) => `${u.bloco}-${u.apartamento}`);
    const naoVotaram = todosApartamentos.filter(
      (ap) => !votaram.includes(ap)
    );
    return { votaram, naoVotaram };
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center min-h-screen text-gray-600">
        Carregando assembleias...
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <Navbar mostrarVoltar={true} />

      <div className="max-w-6xl mx-auto bg-white shadow-lg rounded-2xl p-8 mt-20">
        <h1 className="text-3xl font-bold text-gray-800 mb-6 text-center">
          Gerenciar Assembleias<span className="text-indigo-500">.</span>
        </h1>

        {/* 🔍 Barra de busca e filtro */}
        <div className="flex flex-col md:flex-row items-center justify-between mb-6 gap-3">
          <input
            type="text"
            placeholder="Buscar assembleia..."
            value={busca}
            onChange={(e) => setBusca(e.target.value)}
            className="w-full md:w-1/2 p-3 rounded-xl border border-gray-300 focus:ring-2 focus:ring-indigo-200 outline-none"
          />
          <select
            value={filtro}
            onChange={(e) => setFiltro(e.target.value)}
            className="w-full md:w-1/4 p-3 rounded-xl border border-gray-300 focus:ring-2 focus:ring-indigo-200 outline-none"
          >
            <option value="todas">Todas</option>
            <option value="ativa">Ativas</option>
            <option value="inativa">Inativas</option>
          </select>
        </div>

        {/* 🧾 Tabela de assembleias */}
        <table className="w-full border-collapse">
          <thead>
            <tr className="bg-indigo-100 text-gray-700 text-sm">
              <th className="p-3 text-left">Título</th>
              <th className="p-3 text-left">Data</th>
              <th className="p-3 text-center">Status</th>
              <th className="p-3 text-center">Ações</th>
            </tr>
          </thead>
          <tbody>
            {assembleiasFiltradas.length > 0 ? (
              assembleiasFiltradas.map((a) => (
                <tr
                  key={a.id}
                  className="border-b hover:bg-indigo-50 text-sm text-gray-700"
                >
                  <td className="p-3 font-medium">{a.titulo}</td>
                  <td className="p-3">
                    {new Date(a.data).toLocaleDateString("pt-BR")}
                  </td>
                  <td className="p-3 text-center">
                    {a.status === "ativa" ? (
                      <span className="text-green-600 font-semibold">
                        Ativa
                      </span>
                    ) : (
                      <span className="text-red-600 font-semibold">
                        Inativa
                      </span>
                    )}
                  </td>
                  <td className="p-3 text-center space-x-2">
                    <button
                      onClick={() => alternarStatus(a.id, a.status)}
                      className={`px-4 py-1 rounded-md text-white text-sm shadow-md ${
                        a.status === "ativa"
                          ? "bg-red-500 hover:bg-red-600"
                          : "bg-green-500 hover:bg-green-600"
                      }`}
                    >
                      {a.status === "ativa" ? "Desativar" : "Ativar"}
                    </button>

                    <button
                      onClick={() => verParticipacao(a)}
                      className="px-4 py-1 rounded-md bg-indigo-500 hover:bg-indigo-600 text-white text-sm shadow-md"
                    >
                      Ver participação
                    </button>
                  </td>
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan="4" className="text-center py-6 text-gray-500">
                  Nenhuma assembleia encontrada.
                </td>
              </tr>
            )}
          </tbody>
        </table>

        {/* Modal de participação */}
        {assembleiaSelecionada && (
          <div className="fixed inset-0 flex items-center justify-center bg-black/40 backdrop-blur-sm z-50">
            <div className="bg-white rounded-2xl shadow-xl w-full max-w-2xl p-6 relative">
              <h2 className="text-xl font-bold text-gray-800 mb-4 text-center">
                Participação — {assembleiaSelecionada.titulo}
              </h2>

              <div className="grid grid-cols-2 gap-6">
                {/* Quem votou */}
                <div>
                  <h3 className="font-semibold text-green-600 mb-2">
                    🟢 Votaram
                  </h3>
                  <ul className="list-disc list-inside text-sm text-gray-700 max-h-60 overflow-y-auto">
                    {getParticipacao(assembleiaSelecionada.id).votaram.length >
                    0 ? (
                      getParticipacao(
                        assembleiaSelecionada.id
                      ).votaram.map((ap) => <li key={ap}>{ap}</li>)
                    ) : (
                      <li>Nenhum voto registrado ainda.</li>
                    )}
                  </ul>
                </div>

                {/* Quem não votou */}
                <div>
                  <h3 className="font-semibold text-red-600 mb-2">
                    🔴 Não votaram
                  </h3>
                  <ul className="list-disc list-inside text-sm text-gray-700 max-h-60 overflow-y-auto">
                    {getParticipacao(assembleiaSelecionada.id).naoVotaram.length >
                    0 ? (
                      getParticipacao(
                        assembleiaSelecionada.id
                      ).naoVotaram.map((ap) => <li key={ap}>{ap}</li>)
                    ) : (
                      <li>Todos os apartamentos já votaram 🎉</li>
                    )}
                  </ul>
                </div>
              </div>

              <button
                onClick={() => setAssembleiaSelecionada(null)}
                className="absolute top-2 right-3 text-gray-500 hover:text-gray-700"
              >
                ✖
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
